// File: JvmDemo.java
// Compile: javac JvmDemo.java && java -Xmx256m JvmDemo
import java.lang.management.*;
import java.util.*;

public class JvmDemo {
  public static void main(String[] args) {
    // 1. Runtime memory
    Runtime rt = Runtime.getRuntime();
    System.out.println("available cores: " + rt.availableProcessors());
    System.out.println("max heap       : " + rt.maxMemory() / (1024*1024) + " MB");
    System.out.println("total heap     : " + rt.totalMemory() / (1024*1024) + " MB");
    System.out.println("free heap      : " + rt.freeMemory() / (1024*1024) + " MB");

    // 2. Memory management beans — richer view
    for (MemoryPoolMXBean p : ManagementFactory.getMemoryPoolMXBeans()) {
      MemoryUsage u = p.getUsage();
      System.out.printf("pool: %-30s  used=%d MB  max=%d MB%n",
          p.getName(), u.getUsed()/(1024*1024), u.getMax()/(1024*1024));
    }

    // 3. GC info
    for (GarbageCollectorMXBean gc : ManagementFactory.getGarbageCollectorMXBeans()) {
      System.out.println("gc: " + gc.getName() +
          "  runs=" + gc.getCollectionCount() + "  totalMs=" + gc.getCollectionTime());
    }

    // 4. Force a heap-space OOM (comment out to skip)
    System.out.println("\nallocating a lot to force GC...");
    List<byte[]> waste = new ArrayList<>();
    try {
      for (int i = 0; i < 100_000; i++) waste.add(new byte[1024 * 1024]);   // 1 MB each
    } catch (OutOfMemoryError e) {
      System.out.println("got OOM after allocating " + waste.size() + " MB");
    }

    // 5. Show current thread's stack trace
    System.out.println("\nmy call stack:");
    for (StackTraceElement el : Thread.currentThread().getStackTrace()) {
      System.out.println("  " + el);
    }
  }
}

